### Composable Functions

A **composable** is a function that uses Vue's Composition API to encapsulate and reuse stateful logic:

```js
// useCounter.js
import { ref, computed } from 'vue'

export function useCounter(initialValue = 0) {
  const count = ref(initialValue)
  const double = computed(() => count.value * 2)

  function increment() { count.value++ }
  function decrement() { count.value-- }

  return { count, double, increment, decrement }
}
```

### useMouse Pattern

```js
// useMouse.js
import { ref, onMounted, onUnmounted } from 'vue'

export function useMouse() {
  const x = ref(0)
  const y = ref(0)

  function update(event) {
    x.value = event.pageX
    y.value = event.pageY
  }

  onMounted(() => window.addEventListener('mousemove', update))
  onUnmounted(() => window.removeEventListener('mousemove', update))

  return { x, y }
}
```

Usage:

```vue
<script>
import { useMouse } from './composables/useMouse'
export default {
  setup() {
    const { x, y } = useMouse()
    return { x, y }
  }
}
</script>

<template>Mouse: {{ x }}, {{ y }}</template>
```

### Async Composables

```js
export function useFetch(url) {
  const data = ref(null)
  const error = ref(null)
  const loading = ref(true)

  fetch(url)
    .then(res => res.json())
    .then(json => { data.value = json })
    .catch(err => { error.value = err })
    .finally(() => { loading.value = false })

  return { data, error, loading }
}
```

### Composable Composition

Composables can call other composables:

```js
export function useUser() {
  const { data, loading } = useFetch('/api/user')
  const { x, y } = useMouse()

  return { user: data, loading, mouseX: x, mouseY: y }
}
```

